using UnityEngine;
using System.Collections.Generic;

public class GameController : MonoBehaviour
{
    public GameObject blockPrefab;
    public int gridSizeX = 8;
    public int gridSizeY = 8;
    public int blockSpacing = 10;

    private List<Block> blocks = new List<Block>();
    private GridLayout gridLayout;

    void Start()
    {
        // Create the grid
        gridLayout = new GridLayout(gridSizeX, gridSizeY);
        gridLayout.rowSpacing = blockSpacing;
        gridLayout.columnSpacing = blockSpacing;

        // Create the blocks
        for (int x = 0; x < gridSizeX; x++)
        {
            for (int y = 0; y < gridSizeY; y++)
            {
                Block block = Instantiate(blockPrefab, new Vector3(x * blockSpacing, y * blockSpacing, 0), Quaternion.identity) as Block;
                blocks.Add(block);
            }
        }
    }

    void Update()
    {
        // Check for movements
        for (int i = 0; i < blocks.Count; i++)
        {
            Block block = blocks[i];
            // Check if block can be moved up
            if (block.position.y > 0 && !IsBlockAtPosition(block.position.x, block.position.y - 1))
            {
                block.MoveUp();
            }
            // Check if block can be moved down
            else if (block.position.y < gridSizeY - 1 && !IsBlockAtPosition(block.position.x, block.position.y + 1))
            {
                block.MoveDown();
            }
            // Check if block can be moved left
            else if (block.position.x > 0 && !IsBlockAtPosition(block.position.x - 1, block.position.y))
            {
                block.MoveLeft();
            }
            // Check if block can be moved right
            else if (block.position.x < gridSizeX - 1 && !IsBlockAtPosition(block.position.x + 1, block.position.y))
            {
                block.MoveRight();
            }
        }
    }

    bool IsBlockAtPosition(int x, int y)
    {
        for (int i = 0; i < blocks.Count; i++)
        {
            Block block = blocks[i];
            if (block.position.x == x && block.position.y == y)
            {
                return true;
            }
        }
        return false;
    }
}
